import { useState, useEffect, useCallback } from 'react';
import { Link, NavLink, useNavigate} from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function CrossroadRoadSing() {
    const [tableData, setTableData] = useState([]);
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };


    const transformDataForTable = (data) => {
        if (!Array.isArray(data) || data.length === 0) 
        {
            return [];
        }

        return data.map(
            (item, index) => (
                {
                    id: index + 1,
                    ...item
                }
            )
        );
    };

    // // Delete
    // const deleteRoadSing = async (id) => {
    //     try {
    //         await constFlaskURL.delete(`/roads/sings?id=${id}`);
    //         fetchTableData()
    //     } catch (error) {
    //         console.log(error);
    //     } 
    // }

    // // Put
    // const updateRoadSing = async (id) => {
    //     try {
    //         await constFlaskURL.get(`/road/sing?id=${id}`);
    //         navigate(`/road/edit/${id}`);
    //     } catch (error) {
    //         console.log(error);
    //     } 
    // }

    const fetchTableData = useCallback(async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.get('/roads/sings');

            if (response.status === 200) 
            {
                setTableData(Array.isArray(response.data) ? response.data : [response.data]);
            }
        } 
        catch (err) 
        {
            console.log(err);
        } 
        finally 
        {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        fetchTableData();
    }, [fetchTableData]);

    const transformedData = transformDataForTable(tableData);

    return (
        <div> 
            {loading ? 
            (
                <div>
                    <p>Загрузка данных...</p>
                </div>
            ) : transformedData.length > 0 ? 
            (
                <div>
                    <nav className='navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0'>
                        <div className='container-fluid py-2'>
                            <Link className='navbar-brand fs-3 fw-bold' to='/main'>roads_admin</Link>
                            <div class="btn-group">
                                <button type="button" class="btn btn-info">Пользователь</button>
                                <button type="button" class="btn btn-info dropdown-toggle dropdown-toggle-split" data-bs-toggle="dropdown" aria-expanded="false">
                                    <span class="visually-hidden">Переключатель выпадающего списка</span>
                                </button>
                                <ul class="dropdown-menu">
                                    <li>
                                        <a class="dropdown-item">
                                            <button
                                                onClick={handleLogout} 
                                                className='dropdown-item'
                                                disabled={loading}
                                            >
                                            {loading ? (
                                                <>
                                                    <span className='spinner'></span>
                                                    Выход...
                                                </>
                                                ) : 'Выйти'}
                                            </button>
                                        </a>
                                    </li>
                                </ul>
                            </div>
                        </div>
                        <div className='container-fluid bg-dark py-2'>
                            <div className='navbar-nav flex-row'>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/main' end> Главная </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads' end> Дороги </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/sings' end> Дорожные знаки </NavLink>
                                <NavLink className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/roads/sings' end> Знаки на дорогах </NavLink>
                                <div class="collapse navbar-collapse" id="navbarNavDarkDropdown">
                                    <ul class="navbar-nav">
                                        <li class="nav-item dropdown">
                                            <a class="nav-link dropdown-toggle" href="#" id="navbarDarkDropdownMenuLink" role="button" data-bs-toggle="dropdown" aria-expanded="false">
                                                Перекрестки
                                            </a>
                                            <ul class="dropdown-menu dropdown-menu-dark" aria-labelledby="navbarDarkDropdownMenuLink">
                                                <li>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/crossroads/roads/sings' end> Дорожные знаки на перекрестках</NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/crossroads' end>Перекрестки</NavLink>
                                                    <NavLink style={{ color: 'black' }} className={({ isActive }) => `nav-link me-3 ${isActive ? 'active fw-bold' : ''}`} to='/type_crossroads' end>Типы перекрестков</NavLink>
                                                </li>
                                            </ul>
                                        </li>
                                    </ul>
                                </div>
                            </div>
                        </div>
                    </nav>
                    <div className='container'>
                        <h1>Дорожные знаки на перекрестках.</h1>
                    </div>
                </div>
            ) : (
                <p className='no-data'>Нет данных для отображения</p> 
            )} 
        </div>
    );
}

export default CrossroadRoadSing;
